/* -----------------------------------------------------------------------
 * Binary search
 * --------------------------------------------------------------------- */
static const ChineseChar16_t *find_char(uint16_t gbk)
{
    int lo = 0, hi = (int)CHINESE_CHAR_COUNT - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (g_chinese_chars[mid].gbk == gbk) return &g_chinese_chars[mid];
        if (g_chinese_chars[mid].gbk < gbk) lo = mid + 1;
        else hi = mid - 1;
    }
    return NULL;
}

/* -----------------------------------------------------------------------
 * Draw one 16x16 character  (transparent - only foreground pixels drawn)
 *
 * Transparent mode is used so that Chinese text can be overlaid on any
 * solid-colour background (buttons, dark areas) without leaving a black
 * background rectangle.  The caller is responsible for filling the cell
 * background before calling (e.g. via lcd_fill or lcd_clear).
 * For in-place numeric overwrite, clear the row with lcd_fill first.
 * --------------------------------------------------------------------- */
void lcd_show_chinese_char(uint16_t x, uint16_t y, uint16_t gbk, uint16_t color)
{
    const ChineseChar16_t *rec = find_char(gbk);
    if (!rec) return;

    const uint8_t *bmp = rec->bmp;
    uint8_t row, col;

    for (row = 0; row < 16u; row++) {
        uint8_t hi = bmp[row * 2u];
        uint8_t lo = bmp[row * 2u + 1u];
        /* Only draw pixels that belong to the glyph (foreground only) */
        for (col = 0u; col < 8u; col++) {
            if (hi & (0x80u >> col))
                lcd_draw_point((uint16_t)(x + col), (uint16_t)(y + row), color);
        }
        for (col = 0u; col < 8u; col++) {
            if (lo & (0x80u >> col))
                lcd_draw_point((uint16_t)(x + 8u + col), (uint16_t)(y + row), color);
        }
    }
}

/* -----------------------------------------------------------------------
 * Draw mixed GBK string (ASCII 8x16 + Chinese 16x16)
 * Both ASCII and Chinese parts are drawn in transparent mode.
 * --------------------------------------------------------------------- */
void lcd_show_chinese_str(uint16_t x, uint16_t y, const uint8_t *str, uint16_t color)
{
    uint16_t cx = x;
    while (*str) {
        uint8_t b = *str;
        if (b >= 0x81u && b <= 0xFEu) {
            /* GBK lead byte -> two-byte Chinese char (transparent) */
            uint8_t b2 = *(str + 1u);
            if (b2 == 0u) break;
            uint16_t gbk = ((uint16_t)b << 8u) | b2;
            lcd_show_chinese_char(cx, y, gbk, color);
            cx += 16u;
            str += 2;
        } else {
            /* ASCII character - mode=1 (transparent, no bg fill) */
            lcd_show_char(cx, y, (char)b, 16u, 1u, color);
            cx += 8u;
            str++;
        }
    }
}
